  ('islands-6f0ba476-moex-00054', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '稅捐稽徵法所稱相當擔保係指相當於擔保稅款之擔保品，下列有關相當擔保之敘述，何者錯誤？', '["經中央銀行掛牌之外幣按八折計算", "黃金，按九折計算", "上市或上櫃之有價證券，按八折計算", "政府發行經規定可十足提供公務擔保之公債，按市值計算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00055', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法有關稅捐徵收之規定，下列敘述何者錯誤？', '["已申報且無逃漏情形者，其核課期間為5年", "未申報或以詐欺方式逃漏稅者，其核課期間為7年", "稅捐徵收期間為5年，自核課期間屆滿之翌日起算", "稅捐之徵收，於徵收期間屆滿前已開始執行者，仍得繼續執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00056', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法有關緩繳之規定，下列敘述何者正確？', '["因天災或不可抗力申請緩繳者，其核准期間最長不得逾5年", "申請分期繳納鉅額稅捐者，須按日加計利息", "經核准延期或分期繳納後，如未如期繳納，可再申請延長緩繳期限", "緩繳案件經核准後，稅捐稽徵機關不得要求提供擔保"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00057', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依據稅捐稽徵法之規定，下列有關稅捐行政救濟程序之規定，何者正確？', '["依核定稅額通知書所載有應納稅額或應補徵稅額者，應於繳款書送達後，於繳納期間屆滿之日 起30日內，申請復查", "依核定稅額通知書所載無應納稅額或應補徵稅額者，應於核定稅額通知書送達之日起30日內， 申請復查", "復查之申請，以稅捐稽徵機關收受復查申請書之日期為準", "各稅法規定以公告代替核定稅額通知書之填具及送達者，應於公告之日起30日內，申請復查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00058', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '下列有關稅捐核課期間之敘述，何者錯誤？', '["依法應由稅捐稽徵機關依稅籍底冊課徵之稅捐，其核課期間為5年", "依法應由納稅義務人申報繳納之稅捐，已在規定期間內申報，且無故意以詐欺或其他不正當方 法逃漏稅捐者，其核課期間為5年", "未於規定期間內申報，其核課期間為7年", "在核課期間內未經發現者，以後仍得再補稅處罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00059', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '某公司負責人甲為逃漏公司所得稅，指示會計乙製作虛假發票，使公司短報所得達新臺幣6千萬 元。案發前，甲與乙在未被檢舉、也未被稅捐機關調查前，主動向稅捐機關補報並補繳稅款。下 列敘述何者正確？', '["甲因公司逃漏稅額達5千萬元以上，仍須負刑事責任，且不得免罰", "乙雖僅為協助行為，仍須與甲負相同刑責", "甲與乙主動補報並補繳，在未被檢舉或查獲前，即可免除刑事責任及罰鍰", "甲與乙雖主動補報並補繳，僅得減輕處罰，不得免罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00060', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依房屋稅條例之規定，下列那些情形得免徵房屋稅？①公立醫院之院舍與員工宿舍  ②業經立案', '["政府平價配售之平民住宅", "宗教團體供傳教佈 道之寺廟並完成登記", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00061', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，總機構在我國境外之營利事業，在我國境內經營下列何種業務，其成本費用分攤 計算困難者，得向財政部申請按其在中華民國境內之營業收入之百分之十五為中華民國境內之營利', '["經營國際運輸", "承包營建工程", "出租機器設備", "提供技術服務  ⑤出租影片"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00062', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '依現行所得稅法規定，下列那些所得屬於分離課稅，即扣繳後不併計入綜合所得總額課稅？①政', '["告發或檢舉獎金", "股利所得", "執行業務所得", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00063', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-e38ac4c6', 'sub-islands-6f0ba476-03', NULL, 'single_choice', '假設丙公司國內總公司113年度所得額為新臺幣4,000萬元，在美國分公司當年度所得額為2,500 萬元，已納當地所得稅700萬元，在德國分公司當年度所得額為1,500萬元，已納當地所得稅400 萬元。試問丙公司當年度應納營利事業所得稅為多少元？', '["600萬元", "700萬元", "800萬元", "900萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "9aabb116bb0b", "answer_pdf_sha1": "1881374c0f4c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1211", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL)
